def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 45.0 + np.log1p(cap) * 30 + np.sqrt(item * cap) * 3
        fluctuation = 0.0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.3) - 120 * np.tanh(cap)
            if cap > 12:
                base_priority += 200 * np.cbrt(cap) + 40 * np.sin(cap * 2)
            else:
                base_priority -= 60 * usage + 25 * np.cos(cap)
            for i in range(1, 6):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.9) * 18 / i
            for extra in range(1, 4):
                base_priority += (np.log1p(usage) ** 2) * extra * 10
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 3500 * delta ** 1.9 + 400 * (1 - delta ** 0.7) - 50 * np.sqrt(cap)
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.1)) * 30 / j
            if int(cap * 4) % 5 == 1:
                base_priority += 55 * np.tan(cap / 18)
            if cap < 1:
                base_priority -= 25 * usage
        elif 3 < usage <= 4:
            base_priority += 2000 * (usage - 3) ** 2.2 + 100 * np.sin(cap * 2)
            for k in range(1, 8):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 12 / k
                    if k % 4 == 0:
                        fluctuation += 6 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 1)
                    if k == 6 and usage > 3.5:
                        fluctuation += 25
            if (cap * 7) % 3 < 1:
                base_priority += 45 * np.cos(cap * 4)
        elif 2 < usage <= 3:
            base_priority += 1500 * (usage - 2) ** 2 + 80 * np.sin(cap * 1.5)
            for m in range(1, 14):
                pwr = usage ** m
                if pwr < 0.55:
                    fluctuation += pwr * 18 / m
                    if m % 2 == 0:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 3)
                    if m == 11 and usage > 2.7:
                        fluctuation += 18
            if cap % 3.1 < 0.7:
                base_priority += 32 * np.cos(cap * 3.5)
        elif 1 < usage <= 2:
            base_priority += 950 * (usage - 1) ** 3 + 120 * np.cos(cap * 2)
            fluctuation = 0
            for n in range(1, 18):
                pwr = usage ** n
                if pwr < 0.65:
                    fluctuation += pwr * 22 / n
                    if n % 5 == 2:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - pwr) * 14 / (n + 2)
                    if n == 15 and usage > 1.8:
                        fluctuation += 20
            if cap % 2.0 < 0.4:
                base_priority += 40 * np.sin(cap * 1.8)
        elif 0.3 < usage <= 1:
            base_priority += 140 * (1 - usage) + 50 * np.sqrt(cap)
            for o in range(1, 13):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 15 / o
                if usage < 0.06 * o:
                    fluctuation -= 9 * o
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 300
            elif cap < 1.1:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 7) * 25
        else:
            base_priority += 300 * (1 - usage) ** 2.5 + 70 * np.cos(cap)
            for p in range(1, 21):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 7) - 0.3) * 15 / p
                if usage < 0.01 * p:
                    fluctuation -= 14 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 370
            elif cap < 1.2:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 8) * 35
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 100
            if usage > 0.8:
                priority += 110
            elif usage < 0.15:
                priority -= 70
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 50
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 35
            for s in range(1, 8):
                if int(cap * 1300) % (s + 5) == 1:
                    priority += s * 9
                else:
                    priority -= s * 4
        else:
            if usage < 0.15:
                priority -= 50
                for t in range(1, 9):
                    priority -= t * 7
            elif usage > 0.95:
                priority += 110
                for u in range(1, 7):
                    priority += u * 13
            else:
                priority += 40
        proximity = 0
        checks = [(2500, 17, 20), (1100, 29, -13), (200, 11, 16)]
        for mult, mod_val, prox_add in checks:
            if int(cap * mult) % mod_val == 0:
                proximity += prox_add
        for w in range(1, 11):
            diff = abs(usage - w / 10)
            if diff < 0.015:
                proximity += 25 / w
            elif diff < 0.045:
                proximity += 13 / w
            else:
                proximity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1700) % (x + 11)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1700) % (y + 8)
            if mod_chk == 0:
                proximity += 15 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.004:
            for z in range(1, 9):
                priority -= z * 12
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 14
        if cap > 3.0:
            if cap % 1 < 0.05:
                priority += 50
            if (int(cap * 3000) % 29 == 0) and (usage > 0.75):
                priority += 80
            for bb in range(1, 7):
                if (int(cap * 700) % (bb + 11) == 3) and (usage < 0.9):
                    priority -= 35
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
